    60→      const totalCollected   = students.reduce((s, st) => s + (st.amount || 0), 0);
    61→      const paidCount        = students.filter(s => s.paid).length;
    62→
    63→      const catMap = {};
    64→      expenses.forEach(e => { catMap[e.category] = (catMap[e.category] || 0) + e.spent; });
    65→      const maxCatVal = Math.max(...Object.values(catMap), 1);
    66→
    67→      const catRows = Object.entries(catMap).map(([cat, val]) => `
    68→        <tr><td>${cat}</td><td>₪${val.toLocaleString()}</td>
    69→        <td><div style="background:#e2e8f0;border-radius:4px;height:10px;width:160px">
    70→        <div style="background:#7c3aed;height:10px;border-radius:4px;width:${Math.round((val/maxCatVal)*100)}%"></div>
    71→        </div></td></tr>`).join('');
    72→
    73→      const eventRows = events.map(e => `
    74→        <tr><td>${e.name}</td><td>${formatDate(e.date)}</td><td>${e.category}</td>
    75→        <td>${(e.type||'expense')==='income' ? 'הכנסה' : 'הוצאה'}</td>
    76→        <td>₪${e.budget.toLocaleString()}</td><td>₪${e.spent.toLocaleString()}</td>
    77→        <td>${e.done ? '✅' : '⬜'}</td></tr>`).join('');
    78→
    79→      const membersHtml = (budget.members||[]).length > 0
    80→        ? `<p><strong>חברי הועד:</strong> ${(budget.members||[]).join(', ')}</p>` : '';
    81→      const groupsHtml = (budget.whatsappGroups||[]).length > 0
    82→        ? `<p><strong>קבוצות וואצאפ:</strong> ${(budget.whatsappGroups||[]).map(g => g.name).join(', ')}</p>` : '';
    83→      const collPct = students.length > 0 ? Math.round((paidCount / students.length) * 100) : 0;
    84→      const spentPct = totalBudgetExp > 0 ? Math.round((totalSpent / totalBudgetExp) * 100) : 0;
    85→
    86→      const html = `<!DOCTYPE html><html lang="he" dir="rtl"><head><meta charset="UTF-8">
    87→<title>דו״ח — ${budget.name}</title>
    88→<link href="https://fonts.googleapis.com/css2?family=Heebo:wght@400;700;900&display=swap" rel="stylesheet">
    89→<style>body{font-family:'Heebo',sans-serif;direction:rtl;padding:24px;color:#0f172a;font-size:13px}
    90→h1{font-size:22px;margin-bottom:2px}h2{font-size:15px;margin-top:22px;color:#7c3aed;border-bottom:2px solid #ede9fe;padding-bottom:4px}
    91→.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px}
    92→.stat{background:#f8fafc;border-radius:8px;padding:10px;text-align:center;border:1px solid #e2e8f0}
    93→.sv{font-size:18px;font-weight:900;color:#7c3aed}.sl{font-size:11px;color:#64748b}
    94→table{width:100%;border-collapse:collapse;margin-bottom:12px}
    95→th{background:#f1f5f9;padding:7px;text-align:right;font-size:12px;border:1px solid #e2e8f0}
    96→td{padding:6px 8px;border:1px solid #e2e8f0;font-size:12px}tr:nth-child(even){background:#f8fafc}
    97→.bar{height:12px;background:#e2e8f0;border-radius:4px;margin:4px 0}
    98→.bfill{height:12px;border-radius:4px;background:linear-gradient(90deg,#7c3aed,#db2777)}
    99→.bfill-g{background:linear-gradient(90deg,#059669,#4ade80)}
   100→@media print{body{padding:8px}}</style></head>

